import PhotoCard from '@/components/PhotoCard'
import React from 'react'
import { useSidebar } from '@/hooks/useSidebar'
import { useMediaQuery } from 'usehooks-ts';

const Hero = () => {

    const gridItemIds = ["title", "cards-right", "cards-left", "about"]
    const isMobile = useMediaQuery("(max-width: 992px)"); // usually 768, but need to start mobile breakpoint earlier

    return (
        <div className="h-[calc(100svh-16px)] w-full flex flex-col gap-4 border-debug overflow-y-hidden">
            {isMobile ? (
                <div>
                    ismobile 
                </div>
            ) : ( 
                <div className="grid grid-rows-2 grid-cols-2 h-full w-full gap-6 pt-4 pl-0 pr-0">
                    {gridItemIds.map(id => (
                        <HeroGridItem key={id} id={id} />
                    ))}
                </div>
            )}
        </div>
    )
}

const HeroGridItem = ({ id }: { id: string }) => {
    const isSidebarCollapsed = useSidebar((state) => state.isCollapsed)
    const sidebarWidth = useSidebar((state) => state.width)
    const aboutPTags = [
        "I graduated from the University of Arkansas (May 2025) with a B.S. in Computer Science and a minor in Mathematics.",
        "I build full-stack applications, using modern frameworks and tools, including React, GSAP, Figma, and MongoDB. These projects range from mobile development to machine learning. ",
        "I care about how products look and feel, which is why I gathered feedback from 50+ users before launching this website.",
        "Outside of coding, I enjoy running, hiking, and listening to music. I also love traveling and have visited 10 countries so far.",
    ]

    const titleFontSize = isSidebarCollapsed
        ? undefined
        : `${8 - Math.min(sidebarWidth, 240) * 0.004}rem`
    
    if (id === "title") return (
        <div className="title-wrapper relative border-debug-p overflow-hidden">
        <h4 className="absolute top-0 left-0">
            introducing...
        </h4>
        <div className="abs-x-center bottom-0 flex flex-col gap-6 w-full text-center">
            <h1 className="border-debug-p overflow-hidden text-ellipsis transition-[font-size] duration-300 ease-in-out" style={titleFontSize ? { fontSize: titleFontSize } : undefined}>
                Jordi Castro
            </h1>
            <p className="flex-center gap-3">
                <span className="text-2xl">️
                    🌞🌋🥭
                </span>
                /ˈdʒɔr.di ˈkæs.troʊ/
            </p>
        </div>
    </div>
    )
    else if (id === "cards-right") return (
        <div className="border-debug-p">
            {/* photo cards wrapper */}
            <div className="flex h-full w-full items-end gap-4 overflow-x-hidden">
                <div className="flex shrink-0 justify-start items-end">
                    <PhotoCard src="/images/hero/chilean-mountain.png" alt="chilean-mountain" width={185} height={246} className=""/>
                </div>
                <div className="flex h-full shrink-0 self-stretch items-start justify-center">
                    <PhotoCard src="/images/hero/bucket-hat-jordi.png" alt="bucket-hat-jordi" width={227} height={341} className=""/>
                </div>
                <div className="hidden lg:flex shrink-0 flex-col justify-end items-start">
                    <PhotoCard src="/images/hero/playa-del-amor-landscape.png" alt="playa-del-amor-landscape" width={257} height={192} className=""/>
                    <PhotoCard src="/images/hero/jordo-spiderman.png" alt="jordo-spiderman" width={162} height={215} className="mt-4"/>
                </div>
            </div>
        </div>
    )
    else if (id === "cards-left") return (
        <div className="border-debug-p relative">
            <div className="abs-center flex-center items-start w-full h-4/4 gap-4 overflow-x-hidden">
                    <PhotoCard src="/images/hero/mangos.png" alt="arbol-de-mangos" width={185} height={246} className=""/>
                    <PhotoCard src="/images/hero/iguaçu-brasil.png" alt="iguaçu-brasil" width={226} height={302} className="mt-4"/>
            </div>
        </div>
    )
    else if (id === "about") return (
        <div className="border-debug-p flex-start">
            <div className="flex flex-col items-start justify-start h-full w-full xl:w-5/8">
                <h4>about</h4>
                <div className="flex flex-col gap-4">
                    {aboutPTags.map((p, i) => (
                        <p key={i}>
                            {p}
                        </p>
                    ))}
                </div>
            </div>
        </div>
    )
}

export default Hero